const binary = $input.item.binary || {};

const hasCkimage = Object.keys(binary).some(key => key.startsWith('ckimage'));
const hasCpimage = Object.keys(binary).some(key => key.startsWith('cpimage'));

if (!hasCkimage || !hasCpimage) {
  console.log('缺少 ckimage 或 cpimage 前缀的图片，不进行提取');
  return [{
    json: {
      message: "缺少 ckimage 或 cpimage 前缀的图片，不提取 binary",
      hasCkimage: hasCkimage,
      hasCpimage: hasCpimage,
      extracted: false
    },
    binary: {}
  }];
}

const extractedBinary = {};

const ckKeys = Object.keys(binary).filter(k => k.startsWith('ckimage'));
const cpKeys = Object.keys(binary).filter(k => k.startsWith('cpimage'));

const useCkNumber = ckKeys.length > 1;
const useCpNumber = cpKeys.length > 1;

ckKeys.forEach((key, i) => {
  extractedBinary[useCkNumber ? `ckimage${i + 1}` : 'ckimage'] = { ...binary[key] };
});

cpKeys.forEach((key, i) => {
  extractedBinary[useCpNumber ? `cpimage${i + 1}` : 'cpimage'] = { ...binary[key] };
});

console.log(`成功提取 ckimage 和 cpimage 图片，ckimage: ${ckKeys.length} 张, cpimage: ${cpKeys.length} 张`);

return [{
  json: {
    message: "成功提取 ckimage 和 cpimage 的图片",
    ckimageCount: ckKeys.length,
    cpimageCount: cpKeys.length,
    extracted: true
  },
  binary: extractedBinary
}];

