// ================================================ 
// 处理 webhook 数据 + 生成任务ID和预定义路径 
// ================================================ 

const fs = require('fs'); 
const path = require('path'); 

const items = $input.all(); 
const firstItem = items[0] || {}; 
const body = firstItem.json?.body || {}; 

const basePath = '/home/node/.n8n/AI-WEB'; 

const now = new Date(); 
const yyyy = String(now.getFullYear()); 
const mm = String(now.getMonth() + 1).padStart(2, '0'); 
const dd = String(now.getDate()).padStart(2, '0'); 
const imageBasePath = `${basePath}/${yyyy}/${mm}/${dd}`; 

// 使用task_时间戳_随机字符串格式 
const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'; 
let randomStr = ''; 
for (let i = 0; i < 12; i++) { 
  randomStr += chars.charAt(Math.floor(Math.random() * chars.length)); 
} 

// 【新增】在这里记录工作流的启动时间戳（毫秒）
const workflowStartTime = Date.now();

const taskId = `task_${workflowStartTime}_${randomStr}`; 

const folderPath = path.join(imageBasePath, taskId); 
if (!fs.existsSync(folderPath)) { 
  fs.mkdirSync(folderPath, { recursive: true }); 
  console.log('path节点创建文件夹:', folderPath); 
} 

const n8nHost = 'http://localhost:5678'; 

const processImagePaths = (paths) => { 
  if (!paths || !Array.isArray(paths)) return []; 
  return paths.map(p => { 
    const cleanPath = p.startsWith('/') ? p.substring(1) : p; 
    return `${basePath}/${cleanPath}`; 
  }); 
}; 

const ckimageUrls = processImagePaths(body.ckimage); 
const cpimageUrls = processImagePaths(body.cpimage); 
const allImageUrls = [...ckimageUrls, ...cpimageUrls]; 

console.log('ckimage 完整路径:', ckimageUrls); 
console.log('cpimage 完整路径:', cpimageUrls); 
console.log('所有图片路径:', allImageUrls); 

$execution.customData.set('taskId', taskId); 
$execution.customData.set('basePath', basePath); 
$execution.customData.set('imageBasePath', imageBasePath); 
$execution.customData.set('n8nHost', n8nHost); 

const imageCount = parseInt(body.number) || 1; 

const imageKeys = []; 
for (let i = 1; i <= imageCount; i++) { 
  imageKeys.push(`${i}图`); 
} 

const imageUrls = imageKeys.map((key) => ({ 
  name: key, 
  pollUrl: `${n8nHost}/webhook/poll-image?taskId=${taskId}&imageKey=${key}`, 
  localPath: `${imageBasePath}/${taskId}/${key}.png` 
})); 

console.log('生成的任务ID:', taskId); 
console.log('预定义的图片URLs:', imageUrls); 

return [{ 
  json: { 
    ...firstItem.json, 
    originalBody: body, 
    ckimageUrls: ckimageUrls, 
    cpimageUrls: cpimageUrls, 
    allImageUrls: allImageUrls, 
    totalImages: allImageUrls.length, 
    basePath: basePath, 
    taskId: taskId, 
    imageBasePath: imageBasePath, 
    imageCount: imageCount, 
    imageUrls: imageUrls, 
    folderPath: folderPath, 
    year: yyyy, 
    month: mm, 
    day: dd, 

    // 【核心新增】将启动时间戳输出到 JSON 中，供结尾节点抓取
    workflowStartTime: workflowStartTime, 

    _meta: { 
      generatedAt: new Date().toISOString(), 
      promptReady: true, 
      imageGenerating: true 
    } 
  }, 
  binary: firstItem.binary || {} 
}];

// ================================================ 
// 获取 taskId，计算完整路径，按顺序命名图片 
// 统一 binary 键名为 data，重命名 fileName 为 img_1.png 格式 
// 同时创建日期+taskId的文件夹 
// ================================================ 

const fs = require('fs'); 
const path = require('path'); 

const allItems = $input.all(); 

// 尝试多种方式获取 taskId 
let taskId = ''; 

// 方式1：从当前节点的 json 中获取 
const firstItem = allItems[0] || {}; 
if (firstItem.json?.taskId) { 
  taskId = firstItem.json.taskId; 
} 

// 方式2：从"path"节点获取（生成ID的节点） 
if (!taskId) { 
  try { 
    const basePathItems = $('path').all(); 
    if (basePathItems && basePathItems.length > 0) { 
      taskId = basePathItems[0].json?.taskId || ''; 
    } 
  } catch (e) { 
    console.log('无法从 path 获取 taskId'); 
  } 
} 

// 方式3：从 Respond to Webhook2 节点获取 
if (!taskId) { 
  try { 
    const respondItems = $('Respond to Webhook2').all(); 
    if (respondItems && respondItems.length > 0) { 
      taskId = respondItems[0].json?.taskId || ''; 
    } 
  } catch (e) { 
    console.log('无法从 Respond to Webhook2 获取 taskId'); 
  } 
} 

// 如果还是没有，使用时间戳作为备用 
if (!taskId) { 
  console.log('警告: 未找到 taskId，使用时间戳作为备用'); 
  taskId = `task_${Date.now()}`; 
} 

console.log('获取到的 taskId:', taskId); 

// 生成日期文件夹路径 
const now = new Date(); 
const yyyy = String(now.getFullYear()); 
const mm = String(now.getMonth() + 1).padStart(2, '0'); 
const dd = String(now.getDate()).padStart(2, '0'); 

// 文件夹路径 = 基础路径/日期/taskId 
const basePath = '/home/node/.n8n/AI-WEB'; 
const folderPath = path.join(basePath, yyyy, mm, dd, taskId); 

// 创建文件夹（如果不存在） 
let created = false; 
if (!fs.existsSync(folderPath)) { 
  fs.mkdirSync(folderPath, { recursive: true }); 
  created = true; 
  console.log('创建文件夹:', folderPath); 
} 

// 按顺序为每个 item 分配图片编号（img_1, img_2, img_3...） 
return allItems.map((item, index) => { 
  // 修改命名方式：img_1, img_2, img_3... 
  const imageName = `img_${index + 1}`; 
  const fullImagePath = `${folderPath}/${imageName}.png`; 

  // 获取原始 binary 数据 
  const originalBinary = item.binary || {}; 

  // 修改 binary：将所有键名统一为 "data"，fileName 改为 img_X.png 格式 
  const modifiedBinary = {}; 

  // 取第一个 binary 数据的属性作为模板 
  const firstKey = Object.keys(originalBinary)[0]; 
  const templateData = firstKey ? originalBinary[firstKey] : {}; 

  // 获取原始扩展名 
  const extension = (templateData.fileName || 'image.png').split('.').pop() || 'png'; 
  // 新文件名：img_1.png, img_2.png... 
  const newFileName = `${imageName}.${extension}`; 

  // 统一键名为 "data" 
  modifiedBinary['data'] = { 
    ...templateData, 
    fileName: newFileName 
  }; 

  console.log(`生成文件: ${newFileName}`); 

  return { 
    json: { 
      ...item.json, 
      taskId: taskId, 
      basePath: basePath, 
      imageName: imageName, 
      fullImagePath: fullImagePath, 
      // 传递给 Read/Write Files from Disk 
      savePath: fullImagePath, 
      // 用于创建文件夹 
      folderPath: folderPath, 
      created: created, 
      year: yyyy, 
      month: mm, 
      day: dd 
    }, 
    binary: modifiedBinary 
  }; 
});

// ==========================================
// 【1】获取当前节点的输入数据并处理图片路径
// ==========================================
const items = $input.all();
const imagePaths = [];
let taskId = null;

for (const item of items) {
    const json = item.json || {};

    // 【防空】安全提取 taskId
    if (json.taskId && !taskId) {
        taskId = json.taskId;
    }

    // 【防空】安全提取并清洗图片路径
    if (json.savePath && typeof json.savePath === 'string') {
        const pathParts = json.savePath.split('/');
        const yearIndex = pathParts.indexOf('2026');

        if (yearIndex !== -1) {
            const relativePath = '/' + pathParts.slice(yearIndex).join('/');
            imagePaths.push(relativePath);
        }
    }
}

// ==========================================
// 【2】核心：跨节点精准抓取启动时间（融入第二段的防空与异常捕获机制）
// ==========================================
let startTime = null;

try {
    // 使用 n8n 官方跨节点语法获取 path 节点的数据
    const pathNodeData = $('path').first();

    // 确保数据存在且包含时间戳
    if (pathNodeData?.json?.workflowStartTime) {
        startTime = pathNodeData.json.workflowStartTime;
    } else {
        console.warn('⚠️ 成功访问了 path 节点，但未找到 workflowStartTime 字段');
    }
} catch (e) {
    console.error('❌ 无法访问 path 节点，请检查节点名称是否准确为 "path"。错误信息:', e.message);
}

// 【兜底机制】如果抓取失败，使用当前时间防止报错
if (!startTime) {
    startTime = Date.now();
    console.warn('⚠️ 未获取到有效的启动时间，耗时将显示为 0');
}

// ==========================================
// 【3】计算运行耗时
// ==========================================
const endTime = Date.now();
const durationMs = endTime - startTime;

// 防止出现负数耗时（最小为 0）
const safeDurationMs = Math.max(0, durationMs);

// 转换为秒，保留 2 位小数
const generateSpend = parseFloat((safeDurationMs / 1000).toFixed(2));

// ==========================================
// 【4】构建并返回输出数据
// ==========================================
// 提取第一条原始数据用于透传（防空处理）
const firstItemJson = items[0]?.json || {};

return [{
    json: {
        // 【数据继承】将上游的所有原始数据原封不动地继承下来
        ...firstItemJson, 

        // 当前节点处理后的核心业务字段
        taskId: taskId || 'unknown_task',
        imageCount: imagePaths.length,

        // 【核心修改】直接输出标准的 JSON 数组，方便下游直接遍历使用
        imagePaths: imagePaths, 
        paths: imagePaths,

        // 运行耗时及状态字段
        generate_spend: generateSpend,
        status: "completed",
        finished_at: new Date(endTime).toISOString(),

        // 调试字段（方便排查问题，确认无误后可删除）
        _debug_start_time: startTime,   
        _debug_duration_ms: safeDurationMs 
    }
}];

